const createModal = (place, tries) => {
    console.log('place', place)
    const modal = document.createElement('div');
    modal.classList.add('modal', 'overlay');

    const modalInner = document.createElement('div');
    modalInner.classList.add('modal__inner');

    const modalText = document.createElement('div');
    modalText.classList.add('modal__text', 'modal__text_lg');
    modalText.textContent = 'Congratulation!'

    const modalTextSm = document.createElement('div');
    modalTextSm.classList.add('modal__text', 'modal__text_sm');
    const generateTextSm = () => {
        switch (place) {
            case 0:
                return `Well done! You found them all in ${tries} tries. </br> It's your best result.`;
            case 1:
                return `You did well! You found them all in ${tries} tries. </br> It's your second best result.`;
            default:
                return `You found them all in ${tries} tries.`
        }
    }
    modalTextSm.innerHTML = generateTextSm();

    const modalCloseBtn = document.createElement('button');
    modalCloseBtn.classList.add('modal__close');
    const modalImgBtn = document.createElement('img');
    modalImgBtn.setAttribute("src", 'images/close.svg');
    modalCloseBtn.append(modalImgBtn);

    modalInner.append(modalText);
    modalInner.append(modalTextSm);
    modalInner.append(modalCloseBtn);
    modal.append(modalInner);
    
    const body = document.querySelector('body');
    body.append(modal);

    body.classList.add('overflow-hidden');
    modalCloseBtn.addEventListener('click', () => {
        modal.remove();
        body.classList.remove('overflow-hidden');
    });

    modal.addEventListener('click', (e) => {
        if (e.target === modal) {
            modal.remove();
            body.classList.remove('overflow-hidden');
        }
    });

    window.addEventListener('keydown', function (event) {
        if (event.key === 'Escape') {
            modal.remove();
            body.classList.remove('overflow-hidden');
        }
    });
    return modal;
};

export default createModal;