import createModal from "./modal.js";
import createTable from "./table.js";

const container = document.querySelector('.cards');

const cards = document.querySelectorAll('.card');
const turns = document.querySelector('.turns');
const resetBtn = document.querySelector('.btn__reset');
const startBtn = document.querySelector('[data-is-started]');
const results = document.querySelectorAll('.accordion__panel');
const accordionHeader = document.querySelectorAll('.accordion__header');
const audio = new Audio('./sound/sound.wav');

const createCardSequence = (min, max, len) => {
    const set = new Set();
    while (set.size < len) {
        set.add(Math.floor(Math.random() * (max - min + 1)) + min);
    };
    return Array.from(set);;
};

const createPlayField = (len) => {    
    const sequence = createCardSequence(0, len - 1, len - 1);
    [...cards].forEach((el, index) => el.style.setProperty('order', sequence[index]));
};
createPlayField(cards.length);

const toLocalstorage = (turns, allGames, bestGames) => {
    const date = new Date().toLocaleString('ru');
    const newGame = { turns, date };    

    bestGames.push(newGame);
    bestGames.sort((a, b) => a.turns - b.turns);
    const bestGamesUpdated = bestGames.length < 3 ? bestGames : bestGames.slice(1);
    const score = bestGamesUpdated.findIndex((item) => item.date === date);

    if (allGames.length >= 10) {
        allGames.shift();        
    }
    allGames.push(newGame);
    console.log(bestGamesUpdated, score)
    return [allGames, bestGamesUpdated, score];
};

const addTable = () => {
    const allGames = JSON.parse(localStorage.getItem('games')) ?? [];
    const bestGames = JSON.parse(localStorage.getItem('bestgames')) ?? [];
    if (allGames.length === 0) return;
    const tableAllGames = createTable(allGames);
    const tableBestGames = createTable(bestGames);
    results[0].replaceChildren(tableAllGames);
    if (results[0].style.maxHeight) {
        setTimeout(() => {
            results[0].style.maxHeight = results[0].scrollHeight + "px";
        }, 10);
    };
    results[1].replaceChildren(tableBestGames);
    if (results[1].style.maxHeight) {
        setTimeout(() => {
            results[1].style.maxHeight = results[1].scrollHeight + "px";
        }, 10);
    };
};
addTable();


