const changeBtnText = (flag) => {
    startBtn.dataset.isStarted = flag;
    return flag ? '<span>Finish game</span>' : '<span>Start</span>';    
};

const addTurns = (val) => {
    const text = document.createElement('span');
    text.textContent = 'Turns: '

    const result = document.createElement('span');
    result.setAttribute('data-turns-counter', '');
    result.textContent = val;
    turns.replaceChildren(text, result);
};

let isGameStarted = false;
let turnsCount = 0;

const newGame = () => {
    cards.forEach((card) => card.classList.remove('flipped'));
    container.classList.remove('no-events');
    turns.innerHTML = '';
    startBtn.innerHTML = changeBtnText(isGameStarted);
    turnsCount = 0;
};

//events
startBtn.addEventListener('click', () => {
    if (isGameStarted) {
        startBtn.classList.add('no-events');
        cards.forEach((card) => card.classList.add('flipped'));
        isGameStarted = false;
        startBtn.innerHTML = changeBtnText(isGameStarted);
    } else {
        createPlayField();
        isGameStarted = true;
        newGame();
        addTurns(0);
    }
});

let flippedCards = [];
let cardsOpened = 0;
const isMatched = (coll) => coll[0].dataset.animal === coll[1].dataset.animal;

cards.forEach((card) => card.addEventListener('click', ({ target }) => {
    if (!isGameStarted) {
        isGameStarted = true;
        newGame();
        addTurns(0);        
    }
    const currentCard = target.closest('.card');
    currentCard.classList.add('flipped');
    audio.play();
    flippedCards.push(currentCard);
    const turnsCounter = document.querySelector('[data-turns-counter]');
    if (flippedCards.length > 1) {
        container.classList.add('no-events');
        turnsCount += 1;
        turnsCounter.textContent = turnsCount;

        if (!isMatched(flippedCards)) {
            setTimeout(() => {
                flippedCards.forEach((card) => card.classList.remove('flipped'));
                flippedCards = [];
                container.classList.remove('no-events');
            }, 1300);
        } else {
            flippedCards = [];
            cardsOpened += 2;
            container.classList.remove('no-events');
        }
        if (cardsOpened === cards.length) {            
            const allGames = JSON.parse(localStorage.getItem('games')) ?? [];
            const bestGames = JSON.parse(localStorage.getItem('bestgames')) ?? [];
            const data = toLocalstorage(turnsCount, allGames, bestGames);
            localStorage.setItem('games', JSON.stringify(data[0]));
            localStorage.setItem('bestgames', JSON.stringify(data[1]));
            createModal(data[2], turnsCount);
            addTable();
        }
    }
}));

resetBtn.addEventListener('click', () => {
    isGameStarted = false;
    flippedCards = [];
    newGame();    
    createPlayField();
});

accordionHeader.forEach((el) => {
    el.addEventListener('click', ({ target }) => {
        target.classList.toggle('active');
        const panel = target.nextElementSibling;
        if (panel.style.maxHeight) {
            panel.style.maxHeight = null;
        } else {
            panel.style.maxHeight = panel.scrollHeight + "px";
        }
    });
});
